insert  into `subjects`(`id`,`subject_code`,`subject_name`,`subject_type`,`course_classification`,`syllabus_type`,`memorandum`,`memorandum_year`,`memorandum_category`,`subject_unit`,`lessons`,`pdfs`,`contact_hours`,`prerequisites`,`pre_requisite_to`,`course_description`,`program_mapping_grid`,`course_mapping_grid`,`pilo_outcomes`,`cilo_outcomes`,`learning_outcomes`,`basic_readings`,`extended_readings`,`course_assessment`,`committee_members`,`consultation_schedule`,`prepared_by`,`reviewed_by`,`approved_by`,`created_at`,`updated_at`,`deped_data`,`syllabus_path`,`time_allotment`,`schedule`,`q_1_performance_standards`,`q_1_performance_tasks`,`q_2_performance_standards`,`q_2_performance_tasks`) values 
(4,'GE 2','READINGS IN PHILIPPINE HISTORY','Minor','General Education','CHED',NULL,NULL,NULL,3,'{\"Week 0\":\"Detailed Lesson Content:\\r\\nBCP Vision, Mission, Goals, Objectives, Philosophy and School Organizational Structure School Policies Orientation in Online and Modular Learning System,, Student Intended Learning Outcomes:\\r\\nRecite, internalize and explain the BCP Vision, Mission, Goals, Objectives and Philosophy\\r\\nDeepen knowledge on the school\'s policies, guidelines, rules and regulations.\\r\\nFamiliarize on the new normal system of education through online, modular learning system and Blended Learning Delivery Modality (BLDM),, Assessment: ONSITE: Identify the Vision and Mission statements of BCP.\\r\\nCritically analyze these statements in 500 words, focusing on the following:\\r\\nThe clarity and coherence of the statements.\\r\\nHow these statements reflect the school\'s commitment to education.\\r\\nThe alignment of these statements with the current educational landscape.\\r\\nVerify that the BCP VMGO are align with the school goals thru checklist (PMED tools) OFFSITE: Navigate LMS and know the function of each feature.,, Activities: ON-SITE: Read and internalize the following printed materials for Students and Parents Orientation: OFF-SITE: Presentation and Lecture Discussion (PowerPoint Presentation) of Students and Parents Orientation:,, Learning and Teaching Support Materials:\\r\\nInstructional Materials\\r\\nVideo Presentation of BCP Hymn\\r\\nYouTube Video Title: BESTLINK COLLEGE OF THE PHILIPPINES HYMN (BCP hymn)\\r\\nhttps:\\/\\/www.youtube.com\\/watch?v=NuEYO11Wb4E\\r\\nStudent Hand Book\\r\\nLearning Management System,, Output Materials:\\r\\nCheck alignment report\",\"Week 1\":\"Detailed Lesson Content:\\r\\nMeaning and Relevance of History\\r\\nDistinction Between Primary and Secondary Sources\\r\\nExternal and Internal Criticism\\r\\nRepositories of Primary Sources and Different Kinds of Primary Sources\\r\\n\\r\\n- Overview of History\\r\\n\\r\\n- Historical Method, Historiography, and Historians\\r\\n\\r\\n- Historical Revisionism vs. Historical Distortion,, Student Intended Learning Outcomes:\\r\\nCMO-based: Evaluate primary sources for their credibility, authenticity, and provenance.\\r\\n\\r\\nBook-based: Appreciate the importance of history in the social and national life of the Philippines. Apply the knowledge in historical methodology and philosophy in assessing and analyzing existing historical narratives.,, Assessment: ONSITE: On-site:\\r\\n1. Workbook: Answer pages 18-19\\r\\n2. Teacher-made quiz\\r\\n3. Rubric for activity OFFSITE: Off-site:\\r\\n1. Complete the Week 1 assignment\\r\\nuploaded in your Learning\\r\\nManagement System (LMS). Once\\r\\naccomplished, download and print a\\r\\ncopy, then submit it during the next\\r\\nface-to-face class.,, Activities: ON-SITE: 3. AI Utilization: The students will use\\r\\nGemini AI to gather answer why\\r\\nhistory is important to learn. Then,\\r\\nrandom students will be selected to\\r\\nexplain the result they gathered.\\r\\n2. Round Table: The class will be\\r\\ndivided into five groups and each\\r\\ngroup will access to read the\\r\\nFacebook post of Prof. Alvin\\r\\nCampomanes entitled \\u201cHindi\\r\\nMaihahalintulad ang Kasaysayan sa\\r\\nTsismis\\u201d Then, a representative will be\\r\\ncalled to discuss the insight of the\\r\\ngroup. OFF-SITE: 1. Learning Management System\\r\\n(Week 1)\\r\\n1.1. Preliminary Activity\\r\\n1.2. Lesson Proper\\r\\n1.3. Generalization,, Learning and Teaching Support Materials:\\r\\nOn-site:\\r\\n- Learning Plan\\r\\n- Visual Presentation (PowerPoint, Graphic Organizers, Whiteboard, etc.)\\r\\n- Lecture Notes and Handouts\\r\\n- Workbook (Readings in Philippine History, pages 1-15)\\r\\n- Online Source\\r\\n- AI Tools (ChatGPT, Gemini, etc.)\\r\\n\\r\\nOff-site:\\r\\n- Learning Management System,, Output Materials:\\r\\nOn-site:\\r\\n- Workbook Answer (Compiled in portfolio)\\r\\n- Group Presentation (Rubric)\\r\\n- Quiz Result\\r\\n- Notes\\r\\n- Assignment\\r\\n\\r\\nOff-site:\\r\\n- Compile all downloaded materials from the Learning Management System (LMS) for inclusion in your subject portfolio.\",\"Week 2\":\"Detailed Lesson Content:\\r\\nMeaning and Relevance of History; Distinction of Primary and Secondary Sources; External and Internal Criticism; Repositories of Primary Sources, and Different Kinds of Primary Sources\\r\\n\\r\\n- Primary and Secondary Sources\\r\\n- Kinds, Importance, Availability, Accessibility, Analysis and Interpretation of Sources,, Student Intended Learning Outcomes:\\r\\nCMO-based:\\r\\n- Evaluate primary sources for their credibility, authenticity, and provenance.\\r\\n\\r\\nBook-based:\\r\\n- Appreciate the importance of history in the social and national life of the Philippines.\\r\\n- Apply the knowledge in historical methodology and philosophy in assessing and analyzing existing historical narratives.,, Assessment: ONSITE: On-site:\\r\\n1. Workbook: Answer pages 31-32\\r\\n2. Teacher-made quiz\\r\\n3. Rubric for activity OFFSITE: Off-site:\\r\\n1. Complete the Week 2 assignment\\r\\nuploaded in your Learning\\r\\nManagement System (LMS). Once\\r\\naccomplished, download and print a\\r\\ncopy, then submit it during the next\\r\\nface-to-face class.,, Activities: ON-SITE: 1. The class will be divided into five\\r\\ngroups. Each group will receive a\\r\\nscenario, and they will classify if the\\r\\nsource used is primary or secondary.\\r\\n2. Re-al or Fa-ke: Each group will\\r\\nreceive a mixed of real and fake news\\r\\narticles. Then, they will analyze them\\r\\nto determine which are reliable and\\r\\nwhich are fake news. OFF-SITE: 1. Learning Management System\\r\\n(Week 2)\\r\\n1.1. Preliminary Activity\\r\\n1.2. Lesson Proper\\r\\n1.3. Generalization,, Learning and Teaching Support Materials:\\r\\nOn-site:\\r\\n- Learning Plan\\r\\n- Visual Presentation (PowerPoint, Graphic Organizers, Whiteboard, etc.)\\r\\n- Lecture Notes and Handouts\\r\\n- Sample of Primary and Secondary Sources\\r\\n- Workbook (Readings in Philippine History, pages 20-30\\r\\n- Online Sources\\r\\n\\r\\nOff-site:\\r\\n- Learning Management System,, Output Materials:\\r\\nOn-site:\\r\\n- Workbook Answer (Compiled in portfolio)\\r\\n- Group Presentation (Rubric)\\r\\n- Quiz Result\\r\\n- Notes\\r\\n- Assignment\\r\\n\\r\\nOff-site:\\r\\n- Compile all downloaded materials from the Learning Management System (LMS) for inclusion in your subject portfolio.\",\"Week 3\":\"Detailed Lesson Content:\\r\\nMeaning and Relevance of History; Distinction of Primary and Secondary Sources; External and Internal Criticism; Repositories of Primary Sources, and Different Kinds of Primary Sources\\r\\n- External and Internal Criticism\\r\\n,, Student Intended Learning Outcomes:\\r\\nCMO-Based Outcomes\\r\\n- Evaluate primary sources for their credibility, authenticity, and provenance.\\r\\nBook-Based Outcomes\\r\\n- Appreciate the importance of history in the social and national life of the Philippines.\\r\\n- Apply knowledge of historical methodology and philosophy in assessing and analyzing existing historical narratives.\\r\\n\\r\\n\\r\\n,, Assessment: ONSITE: On-Site Activities\\r\\n- Workbook \\u2013 Answer pages 46\\u201347\\r\\n- Teacher-Made Quiz\\r\\n- Rubric-Based Activity\\r\\nOff-Site Activities\\r\\n- Week 3 Assignment \\u2013 Complete the task uploaded in your Learning Management System (LMS).\\r\\n- Once accomplished, download and print a copy.\\r\\n- Submit the printed copy during the next class session.\\r\\n OFFSITE: Off-Site Activities\\r\\n- Week 3 Assignment \\u2013 Complete the task uploaded in your Learning Management System (LMS).\\r\\n- Once accomplished, download and print a copy.\\r\\n- Submit the printed copy during the next class session.,, Activities: ON-SITE: Classroom Activities\\r\\n- Debate\\r\\n- The class will be divided into two groups.\\r\\n- Each group will debate the topic: \\u201cIs history about the truth or about the facts?\\u201d\\r\\n- Group Activity: Historical Picture Analysis\\r\\n- The class will be divided into five groups.\\r\\n- Each group will receive a historical picture.\\r\\n- Members will apply external and internal criticism to evaluate the source.\\r\\n- Two representatives from each group will present the group\\u2019s findings to the class.\\r\\n OFF-SITE: 1. Learning Management System\\r\\n(Week 3)\\r\\n1.1. Preliminary Activity\\r\\n1.2. Lesson Proper\\r\\n1.3. Generalization,, Learning and Teaching Support Materials:\\r\\nOn-Site Learning Materials\\r\\n- Learning Plan\\r\\n- Visual Presentation (PowerPoint, Graphic Organizers, Whiteboard, etc.)\\r\\n- Lecture Notes and Handouts\\r\\n- Historical Photographs\\r\\n- Workbook (Readings in Philippine History, pages 33\\u201346)\\r\\n- Online Sources\\r\\nOff-Site Learning Materials\\r\\n- Learning Management System (LMS)\\r\\n,, Output Materials:\\r\\nHere\\u2019s a polished and well-structured version of your text:\\r\\n\\r\\nOn-Site Requirements\\r\\n- Workbook Answers (compiled in portfolio)\\r\\n- Group Presentation (evaluated using rubric)\\r\\n- Quiz Results\\r\\n- Notes\\r\\n- Assignment\\r\\nOff-Site Requirements\\r\\n- Learning Management System (LMS) \\u2013 Compile all downloaded materials for inclusion in your subject portfolio.\",\"Week 4\":\"Detailed Lesson Content:\\r\\nContent and Contextual Analysis of Selected Primary Sources\\r\\n- Content and Context Analysis\\r\\n- Identification of the Historical Importance of the Text\\r\\n- Examination of the Author\\u2019s Main Argument and Point of View\\r\\nKey Focus Areas\\r\\n- Content and Context Analysis\\r\\n- Historical Biases\\r\\n- Antonio Pigafetta: First Voyage Around the World\\r\\n,, Student Intended Learning Outcomes:\\r\\nCMO-Based Outcomes\\r\\n- Analyze the context, content, and perspective of different kinds of primary sources\\r\\n- Determine the contribution of different kinds of primary sources in u